1	//! Top-level and declaration parsing.
2	
3	use tc24r_ast::{Expr, Function, GlobalDecl, Param, Program, Type};
4	use tc24r_error::CompileError;
5	use tc24r_parse_stream::TokenStream;
6	use tc24r_token::TokenKind;
7	
8	use crate::stmt::{parse_block, skip_fn_ptr_params};
9	use tc24r_parse_stream::try_parse_interrupt_attr;
10	
11	pub use tc24r_parser_types::parse_type;
12	use tc24r_parser_types::{is_base_type, is_storage_class, is_typedef_name};
13	
14	/// Parse a constant integer expression between array brackets.
15	/// Supports integer literals, +, -, *, /, parentheses.
16	pub(crate) fn parse_const_array_size(ts: &mut TokenStream) -> Result<usize, CompileError> {
17	    let val = const_add_sub(ts)?;
18	    if val < 0 {
19	        return Err(CompileError::new(
20	            "array size must be positive",
21	            Some(ts.current_span()),
22	        ));
23	    }
24	    Ok(val as usize)
25	}
26	
27	fn const_add_sub(ts: &mut TokenStream) -> Result<i32, CompileError> {
28	    let mut left = const_mul_div(ts)?;
29	    loop {
30	        if ts.eat(TokenKind::Plus) {
31	            left += const_mul_div(ts)?;
32	        } else if ts.eat(TokenKind::Minus) {
33	            left -= const_mul_div(ts)?;
34	        } else {
35	            break;
36	        }
37	    }
38	    Ok(left)
39	}
40	
41	fn const_mul_div(ts: &mut TokenStream) -> Result<i32, CompileError> {
42	    let mut left = const_primary(ts)?;
43	    loop {
44	        if ts.eat(TokenKind::Star) {
45	            left *= const_primary(ts)?;
46	        } else if ts.eat(TokenKind::Slash) {
47	            let right = const_primary(ts)?;
48	            if right == 0 {
49	                return Err(CompileError::new(
50	                    "division by zero in constant expression",
51	                    Some(ts.current_span()),
52	                ));
53	            }
54	            left /= right;
55	        } else {
56	            break;
57	        }
58	    }
59	    Ok(left)
60	}
61	
62	fn const_primary(ts: &mut TokenStream) -> Result<i32, CompileError> {
63	    if let TokenKind::IntLit(v) = ts.peek().kind {
64	        ts.advance();
65	        return Ok(v);
66	    }
67	    if ts.eat(TokenKind::LParen) {
68	        let val = const_add_sub(ts)?;
69	        ts.expect(TokenKind::RParen)?;
70	        return Ok(val);
71	    }
72	    if ts.eat(TokenKind::Minus) {
73	        return Ok(-const_primary(ts)?);
74	    }
75	    Err(CompileError::new(
76	        "expected integer constant in array size",
77	        Some(ts.current_span()),
78	    ))
79	}
80	
81	/// Check if current position is an enum definition (`enum {` or `enum tag {`).
82	fn is_enum_definition(ts: &TokenStream) -> bool {
83	    if !matches!(ts.peek().kind, TokenKind::Enum) {
84	        return false;
85	    }
86	    match ts.lookahead(1) {
87	        TokenKind::LBrace => true,
88	        TokenKind::Ident(_) => matches!(ts.lookahead(2), TokenKind::LBrace),
89	        _ => false,
90	    }
91	}
92	
93	/// Parse a full program (sequence of functions and globals).
94	pub fn parse_program(ts: &mut TokenStream) -> Result<Program, CompileError> {
95	    let mut functions = Vec::new();
96	    let mut globals = Vec::new();
97	    while !ts.at_eof() {
98	        // Top-level enum definition: consume and register constants
99	        if is_enum_definition(ts) {
100	            ts.advance(); // consume `enum`
101	            tc24r_parser_enum::parse_enum_decl(ts)?;
102	            continue;
103	        }
104	        // Top-level struct/union: definition, variable, or function return type.
105	        // Only intercept struct definitions (with { body }) and struct variable
106	        // declarations. Functions returning struct pointers fall through to
107	        // is_global_decl / parse_function.
108	        if matches!(ts.peek().kind, TokenKind::Struct | TokenKind::Union) {
109	            if is_struct_def_or_var(ts) {
110	                let parsed_ty = parse_type(ts)?; // registers the struct in ts.struct_types
111	                if ts.eat(TokenKind::Semicolon) {
112	                    continue; // standalone definition: struct tag { ... };
113	                }
114	                let name = ts.expect_ident()?;
115	                let mut ty = parsed_ty;
116	                // Handle array suffixes: struct symbol symtab[8][4];
117	                let mut dims = Vec::new();
118	                while ts.eat(TokenKind::LBracket) {
119	                    let size = parse_const_array_size(ts)?;
120	                    ts.expect(TokenKind::RBracket)?;
121	                    dims.push(size);
122	                }
123	                for &size in dims.iter().rev() {
124	                    ty = Type::Array(Box::new(ty), size);
125	                }
126	                // Optional initializer: struct s x = { ... };
127	                let init = if ts.eat(TokenKind::Assign) {
128	                    if ts.check(&TokenKind::LBrace) {
129	                        ts.expect(TokenKind::LBrace)?;
130	                        let mut stores = Vec::new();
131	                        let max_top_idx = crate::stmt::init_braced(ts, &ty, 0, &mut stores)?;
132	                        ts.expect(TokenKind::RBrace)?;
133	                        // Infer size for implicit-size arrays
134	                        if let Type::Array(elem, 0) = &ty {
135	                            ty = Type::Array(elem.clone(), max_top_idx);
136	                        }
137	                        Some(Expr::InitList(flatten_stores_to_init(&ty, &stores)))
138	                    } else {
139	                        Some(crate::expr::parse_expr(ts)?)
140	                    }
141	                } else {
142	                    None
143	                };
144	                ts.expect(TokenKind::Semicolon)?;
145	                globals.push(GlobalDecl { name, ty, init });
146	                continue;
147	            }
148	            // Otherwise: function returning struct pointer — fall through
149	        }
