// tc24r demo63 -- adjacent string-literal concatenation (C99 phase 6)
//
// Verifies:
//   - basic two-chunk concat in a return expression
//   - N-chunk concat across newlines
//   - per-chunk escape resolution: "ab\n" "cd" yields 5 bytes
//   - char[] size inference uses the concatenated length, not the
//     first chunk's length
//   - mixing concat with a call argument
//
// Expected: r0 = 63, UART output: "D63OK"

#include <stdio.h>

char *greeting(void) {
    return "hello, "
           "world!"
           " "
           "D63";
}

int main(void) {
    /* Per-chunk escape resolution: "ab\n" + "cd" must be 5 chars
       ('a','b','\n','c','d') and a 6-byte sizeof including the null. */
    char esc[] = "ab\n" "cd";
    if (sizeof(esc) != 6) return 1;
    if (esc[0] != 'a' || esc[1] != 'b' || esc[2] != '\n' ||
        esc[3] != 'c' || esc[4] != 'd' || esc[5] != 0) {
        return 2;
    }

    /* Multi-chunk implicit-size local array. */
    char abc[] = "ab" "cd" "ef" "gh";
    if (sizeof(abc) != 9) return 3;
    if (abc[0] != 'a' || abc[7] != 'h' || abc[8] != 0) return 4;

    /* Function returning concatenated string. */
    char *g = greeting();
    if (g[0] != 'h' || g[7] != 'w' || g[13] != ' ') return 5;
    if (g[14] != 'D' || g[15] != '6' || g[16] != '3' || g[17] != 0) return 6;

    /* In a function call argument. */
    printf("D63" "OK\n");
    return 63;
}

