// tc24r demo63 -- adjacent string-literal concatenation (C99 phase 6)
//
// Verifies end-to-end:
//   - basic two-chunk concat in a return expression (function returns
//     pointer to a single concatenated rodata literal)
//   - N-chunk concat across newlines
//   - per-chunk escape resolution: "ab\n" "cd" yields a single 6-byte
//     literal in .data with the bytes {a,b,'\n',c,d,0}
//   - concat in a function-call argument
//   - sizeof(char[] = "abc" "def") reports 7, not 4
//
// NOTE: indexing into a `char esc[] = "...";` local is a separate
// pre-existing codegen issue (the local is stored as a pointer to
// rodata; subscripting it reads the pointer's bytes). This demo
// avoids that path; the size-inference fix is verified via sizeof
// only, and string contents via globals + return values.
//
// Expected: r0 = 63, UART output: "D63OK"

#include <stdio.h>

