    char *gr = greeting();
    if (gr[0] != 'h' || gr[7] != 'w' || gr[13] != ' ') return 5;
    if (gr[14] != 'D' || gr[15] != '6' || gr[16] != '3' || gr[17] != 0) return 6;

    /* In a function call argument. */
    printf("D63" "OK\n");
    return 63;
}

