1	// tc24r demo45 -- Lisp eval: (+ 40 2) => 42
2	//
3	// Implements: reader + eval + builtins
4	//   - read_val: parse S-expressions from a string
5	//   - eval: numbers self-evaluate, (+ a b), (- a b), (* a b),
6	//           (quote x), (if c t e), (cons a b), (car x), (cdr x)
7	//   - Environment as association list
8	//
9	// Expected: r0 = 42, UART output: "D45OK"
10	
11	#include <stdio.h>
12	#include <stdlib.h>
13	#include <string.h>
14	
15	// --- Value types ---
16	
17	enum { T_NUM, T_SYM, T_CONS, T_NIL };
18	
19	struct val {
20	    int tag;
21	    int num;
22	    char *sym;
23	    struct val *car;
24	    struct val *cdr;
25	};
26	
27	// --- Constructors ---
28	
29	struct val *make_nil(void);
30	struct val *make_num(int n);
31	struct val *make_sym(char *s);
32	struct val *cons(struct val *a, struct val *d);
33	struct val *eval(struct val *x, struct val *env);
34	
35	struct val *NIL;
36	
37	struct val *make_nil(void) {
38	    struct val *v = (struct val *)malloc(15);
39	    v->tag = T_NIL;
40	    return v;
41	}
42	
43	struct val *make_num(int n) {
44	    struct val *v = (struct val *)malloc(15);
45	    v->tag = T_NUM;
46	    v->num = n;
47	    return v;
48	}
49	
50	struct val *make_sym(char *s) {
51	    struct val *v = (struct val *)malloc(15);
52	    v->tag = T_SYM;
53	    v->sym = s;
54	    return v;
55	}
56	
57	struct val *cons(struct val *a, struct val *d) {
58	    struct val *v = (struct val *)malloc(15);
59	    v->tag = T_CONS;
60	    v->car = a;
61	    v->cdr = d;
62	    return v;
63	}
64	
65	struct val *car(struct val *x) { return x->car; }
66	struct val *cdr(struct val *x) { return x->cdr; }
67	
68	int atom(struct val *x) { return x->tag != T_CONS; }
69	int null(struct val *x) { return x->tag == T_NIL; }
70	
71	// --- Printer ---
72	
73	void print_val(struct val *x) {
74	    if (x->tag == T_NUM) {
75	        printf("%d", x->num);
76	    } else if (x->tag == T_SYM) {
77	        printf("%s", x->sym);
78	    } else if (x->tag == T_NIL) {
79	        printf("nil");
80	    } else if (x->tag == T_CONS) {
81	        printf("(");
82	        print_val(x->car);
83	        struct val *rest = x->cdr;
84	        while (rest->tag == T_CONS) {
85	            printf(" ");
86	            print_val(rest->car);
87	            rest = rest->cdr;
88	        }
89	        if (rest->tag != T_NIL) {
90	            printf(" . ");
91	            print_val(rest);
92	        }
93	        printf(")");
94	    }
95	}
96	
97	// --- Reader (from string) ---
98	
99	char *_input;
100	int _pos;
101	
102	char peek(void) { return _input[_pos]; }
103	char next(void) { char c = _input[_pos]; _pos++; return c; }
104	
105	void skip_ws(void) {
106	    while (peek() == 32 || peek() == 10 || peek() == 9) {
107	        next();
108	    }
109	}
110	
111	struct val *read_val(void);
112	
113	struct val *read_list(void) {
114	    skip_ws();
115	    if (peek() == ')') {
116	        next();
117	        return NIL;
118	    }
119	    struct val *first = read_val();
120	    struct val *rest = read_list();
121	    return cons(first, rest);
122	}
123	
124	struct val *read_val(void) {
125	    skip_ws();
126	    char c = peek();
127	
128	    // Number
129	    if ((c >= '0' && c <= '9') || (c == '-' && _input[_pos + 1] >= '0' && _input[_pos + 1] <= '9')) {
130	        int sign = 1;
131	        if (c == '-') { sign = -1; next(); }
132	        int n = 0;
133	        while (peek() >= '0' && peek() <= '9') {
134	            n = n * 10 + (next() - '0');
135	        }
136	        return make_num(n * sign);
137	    }
138	
139	    // List
140	    if (c == '(') {
141	        next();
142	        return read_list();
143	    }
144	
145	    // Symbol
146	    char buf[16];
147	    int i = 0;
148	    while (peek() != 0 && peek() != ' ' && peek() != ')' && peek() != '(' && peek() != 10 && i < 15) {
149	        buf[i] = next();
150	        i++;
151	    }
152	    buf[i] = 0;
153	
154	    // Copy symbol name to heap
155	    char *name = (char *)malloc(i + 1);
156	    strcpy(name, buf);
157	    return make_sym(name);
158	}
159	
160	struct val *read_str(char *s) {
161	    _input = s;
162	    _pos = 0;
163	    return read_val();
164	}
165	
166	// --- Environment (association list) ---
167	
168	struct val *env_lookup(struct val *sym, struct val *env) {
169	    while (env->tag == T_CONS) {
170	        struct val *pair = env->car;
171	        if (strcmp(pair->car->sym, sym->sym) == 0) {
172	            return pair->cdr;
173	        }
174	        env = env->cdr;
175	    }
176	    return NIL;
177	}
178	
179	struct val *env_bind(struct val *sym, struct val *val, struct val *env) {
180	    return cons(cons(sym, val), env);
181	}
182	
183	// --- Eval ---
184	
185	struct val *evlis(struct val *args, struct val *env) {
186	    if (null(args)) return NIL;
187	    return cons(eval(car(args), env), evlis(cdr(args), env));
188	}
189	
190	struct val *eval(struct val *x, struct val *env) {
191	    // Numbers are self-evaluating
192	    if (x->tag == T_NUM) return x;
193	    if (x->tag == T_NIL) return x;
194	
195	    // Symbol lookup
196	    if (x->tag == T_SYM) {
197	        return env_lookup(x, env);
198	    }
199	
200	    // List: (fn args...)
201	    struct val *fn = car(x);
202	    struct val *args = cdr(x);
203	
204	    // Special forms
205	    if (fn->tag == T_SYM) {
206	        // (quote x)
207	        if (strcmp(fn->sym, "quote") == 0) {
208	            return car(args);
209	        }
210	        // (if cond then else)
211	        if (strcmp(fn->sym, "if") == 0) {
212	            struct val *cond = eval(car(args), env);
213	            if (!null(cond) && !(cond->tag == T_NUM && cond->num == 0)) {
214	                return eval(car(cdr(args)), env);
215	            } else {
216	                return eval(car(cdr(cdr(args))), env);
217	            }
218	        }
219	    }
220	
221	    // Evaluate arguments for builtins
222	    struct val *eargs = evlis(args, env);
223	    struct val *a = car(eargs);
224	    struct val *b = car(cdr(eargs));
225	
226	    if (fn->tag == T_SYM) {
227	        if (strcmp(fn->sym, "+") == 0) return make_num(a->num + b->num);
228	        if (strcmp(fn->sym, "-") == 0) return make_num(a->num - b->num);
229	        if (strcmp(fn->sym, "*") == 0) return make_num(a->num * b->num);
230	        if (strcmp(fn->sym, "/") == 0) return make_num(a->num / b->num);
231	        if (strcmp(fn->sym, "cons") == 0) return cons(a, b);
232	        if (strcmp(fn->sym, "car") == 0) return car(a);
233	        if (strcmp(fn->sym, "cdr") == 0) return cdr(a);
234	        if (strcmp(fn->sym, "eq") == 0) {
235	            if (a->tag == T_NUM && b->tag == T_NUM) {
236	                return make_num(a->num == b->num);
237	            }
238	            return NIL;
239	        }
240	        if (strcmp(fn->sym, "atom") == 0) return make_num(atom(a));
241	    }
242	
243	    return NIL;
244	}
245	
246	// --- Tests ---
247	
