//! tc24r -- Tiny C compiler targeting the COR24 ISA.

use std::path::Path;
use std::process;

fn main() {
    let args: Vec<String> = std::env::args().collect();

    if args.len() < 2 {
        eprintln!("usage: tc24r <input.c> [-o output.s] [-I dir]");
        process::exit(1);
    }

    let input_path = &args[1];
    let source = read_source(input_path);
    let source_dir = Path::new(input_path).parent();
    let include_dirs = collect_include_dirs(&args);
    let output = compile(&source, source_dir, &include_dirs);
    write_output(&args, &output);
}

fn read_source(path: &str) -> String {
    match std::fs::read_to_string(path) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("tc24r: cannot read {path}: {e}");
            process::exit(1);
        }
    }
}

fn collect_include_dirs(args: &[String]) -> Vec<String> {
    args.windows(2)
        .filter(|w| w[0] == "-I")
        .map(|w| w[1].clone())
        .collect()
}

fn compile(source: &str, source_dir: Option<&Path>, include_dirs: &[String]) -> String {
    let sys_paths: Vec<&Path> = include_dirs.iter().map(|s| Path::new(s.as_str())).collect();
    let preprocessed = tc24r_preprocess::preprocess(source, source_dir, &sys_paths);
    let tokens = match tc24r_lexer::Lexer::new(&preprocessed).tokenize() {
        Ok(t) => t,
        Err(e) => {
            eprintln!("tc24r: {e}");
            process::exit(1);
        }
    };

    let program = match tc24r_parser::parse(tokens) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("tc24r: {e}");
            process::exit(1);
        }
    };

    tc24r_codegen::Codegen::new().generate(&program)
}

fn write_output(args: &[String], output: &str) {
    let output_path = args
        .windows(2)
        .find(|w| w[0] == "-o")
        .map(|w| w[1].as_str());

    match output_path {
        Some(path) => {
            if let Err(e) = std::fs::write(path, output) {
                eprintln!("tc24r: cannot write {path}: {e}");
                process::exit(1);
            }
        }
        None => print!("{output}"),
    }
}

//! Expression AST nodes.

/// An expression node.
#[derive(Debug, Clone)]
pub enum Expr {
    IntLit(i32),
    StringLit(String),
    Ident(String),
    Assign {
        name: String,
        value: Box<Expr>,
    },
    Call {
        name: String,
        args: Vec<Expr>,
    },
    /// Indirect call through expression: expr(args)
    IndirectCall {
        callee: Box<Expr>,
        args: Vec<Expr>,
    },
    BinOp {
        op: BinOp,
        lhs: Box<Expr>,
        rhs: Box<Expr>,
    },
    UnaryOp {
        op: UnaryOp,
        operand: Box<Expr>,
    },
    /// Address-of: &expr
    AddrOf(Box<Expr>),
    /// Pointer dereference: *p
    Deref(Box<Expr>),
    /// Cast expression: (type)expr
    Cast {
        ty: crate::Type,
        expr: Box<Expr>,
    },
    /// Dereference assignment: *p = val
    DerefAssign {
        ptr: Box<Expr>,
        value: Box<Expr>,
    },
    /// Pre-increment: ++lvalue (returns new value)
    PreInc(Box<Expr>),
    /// Pre-decrement: --lvalue (returns new value)
    PreDec(Box<Expr>),
    /// Post-increment: lvalue++ (returns old value)
    PostInc(Box<Expr>),
    /// Post-decrement: lvalue-- (returns old value)
    PostDec(Box<Expr>),
    /// Struct member access: expr.member
    MemberAccess {
        object: Box<Expr>,
        member: String,
    },
    /// Struct member assignment: expr.member = value
    MemberAssign {
        object: Box<Expr>,
        member: String,
        value: Box<Expr>,
    },
    /// GCC statement expression: ({ stmt1; stmt2; expr; })
    StmtExpr(crate::Block),
    /// sizeof applied to an expression: sizeof x, sizeof(expr)
    SizeofExpr(Box<Expr>),
    /// Ternary: cond ? then_expr : else_expr
    Ternary {
        cond: Box<Expr>,
        then_expr: Box<Expr>,
        else_expr: Box<Expr>,
    },
    /// Initializer list: {1, 2, 3} — used for global/static array init
    InitList(Vec<Expr>),
}

/// Binary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum BinOp {
    Add,
    Sub,
    Mul,
    Div,
    Mod,
    BitAnd,
    BitOr,
    BitXor,
    Shl,
    Shr,
    Eq,
    Ne,
    Lt,
    Gt,
    Le,
    Ge,
    LogAnd,
    LogOr,
    Comma,
}

/// Unary operator.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum UnaryOp {
    Neg,
    BitNot,
    LogNot,
}

