                end += 1;
            }
            if end > start {
                let candidate = &asm[start..end];
                if funcs.contains(candidate) {
                    out.push(candidate.to_string());
                }
            }
            i = end;
        } else {
            i += 1;
        }
    }
}

fn is_sym_byte(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

