1	//! Data section emission.
2	
3	use tc24r_ast::{Expr, Program, Type};
4	use tc24r_codegen_state::CodegenState;
5	use tc24r_emit_macros::emit;
6	
7	/// Emit the `.data` section for globals and string literals.
8	pub fn emit_data_section(state: &mut CodegenState, program: &Program) {
9	    let has_globals = !program.globals.is_empty();
10	    let has_strings = !state.string_literals.is_empty();
11	    if !has_globals && !has_strings {
12	        return;
13	    }
14	    emit!(state, "");
15	    emit!(state, "        .data");
16	    for g in &program.globals {
17	        let name = &g.name;
18	        emit!(state, "_{name}:");
19	        match &g.init {
20	            Some(Expr::InitList(values)) => {
21	                let mut iter = values.iter();
22	                emit_typed_data(state, &g.ty, &mut iter);
23	            }
24	            Some(Expr::StringLit(s)) => {
25	                let bytes: Vec<String> = s
26	                    .bytes()
27	                    .chain(std::iter::once(0))
28	                    .map(|b| b.to_string())
29	                    .collect();
30	                let byte_str = bytes.join(",");
31	                emit!(state, "        .byte   {byte_str}");
32	                // Pad if declared array is larger
33	                if let Type::Array(_, count) = &g.ty {
34	                    let pad = count.saturating_sub(s.len() + 1);
35	                    for _ in 0..pad {
36	                        emit!(state, "        .byte   0");
37	                    }
38	                }
39	            }
40	            Some(Expr::IntLit(v)) => {
41	                emit_scalar_or_fill(state, &g.ty, *v);
42	            }
43	            _ => {
44	                emit_zero_fill(state, &g.ty);
45	            }
46	        }
47	    }
48	    for (i, s) in state.string_literals.clone().iter().enumerate() {
49	        emit!(state, "_S{i}:");
50	        let bytes: Vec<String> = s
51	            .bytes()
52	            .chain(std::iter::once(0))
53	            .map(|b| b.to_string())
54	            .collect();
55	        let byte_str = bytes.join(",");
56	        emit!(state, "        .byte   {byte_str}");
57	    }
58	}
59	
60	/// Emit data for a type, consuming values from the iterator in leaf order.
61	fn emit_typed_data<'a>(
62	    state: &mut CodegenState,
63	    ty: &Type,
64	    values: &mut impl Iterator<Item = &'a Expr>,
65	) {
66	    match ty {
67	        Type::Char | Type::UnsignedChar => {
68	            let val = values
69	                .next()
70	                .map(|e| match e {
71	                    Expr::IntLit(v) => *v,
72	                    _ => 0,
73	                })
74	                .unwrap_or(0);
75	            emit!(state, "        .byte   {val}");
76	        }
77	        Type::Array(elem, count) => {
78	            for _ in 0..*count {
79	                emit_typed_data(state, elem, values);
80	            }
81	        }
82	        Type::Struct { members, .. } => {
83	            let mut prev_end = 0i32;
84	            for m in members {
85	                // Emit zero padding between members
86	                let gap = m.offset - prev_end;
87	                for _ in 0..gap {
88	                    emit!(state, "        .byte   0");
89	                }
90	                emit_typed_data(state, &m.ty, values);
91	                prev_end = m.offset + m.ty.size();
92	            }
93	        }
94	        _ => {
95	            // Int, Ptr, UnsignedInt, Void — all 3-byte words
